#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cstdint>
#include <tuple>
#include <algorithm>
#include <pybind11/stl.h>

// Problem 038 — Flux multi-head RMSNorm applied to both Q and K.
//
// The reference is six PyTorch kernels and ~5.5x the minimum HBM traffic.
// This kernel fuses everything into one pass: read each Q/K element once,
// compute the per-head RMS over the contiguous head_dim=128, apply the
// per-head learnable scale, and write the two outputs.  All I/O is float4
// vectorized and tagged streaming (Q/K/Qn/Kn are touched exactly once), so
// the kernel is at the 16 B/elem HBM floor.  head_dim=128 = 32 lanes x 4
// floats, so one warp reduces a full row with only warp-shuffle traffic.

static constexpr int HEAD_DIM = 128;
static constexpr int NUM_HEADS = 48;
static constexpr int WARP_SIZE = 32;
static constexpr int SM_COUNT = 148;
static constexpr int MAX_BLOCKS_PER_SM = 16;
static constexpr int MAX_BLOCKS = SM_COUNT * MAX_BLOCKS_PER_SM;

__device__ __forceinline__ float warp_reduce_sum(float v) {
    constexpr unsigned mask = 0xffffffffU;
    #pragma unroll
    for (int offset = WARP_SIZE / 2; offset > 0; offset >>= 1) {
        v += __shfl_down_sync(mask, v, offset);
    }
    // broadcast lane-0 total to the whole warp
    v = __shfl_sync(mask, v, 0);
    return v;
}

__device__ __forceinline__ float4 mul_rms_weight(float4 x, float inv_rms, float4 w) {
    // Match reference order: (x * rsqrt(mean+eps)) * weight
    float4 out;
    out.x = (x.x * inv_rms) * w.x;
    out.y = (x.y * inv_rms) * w.y;
    out.z = (x.z * inv_rms) * w.z;
    out.w = (x.w * inv_rms) * w.w;
    return out;
}

template <int THREADS>
__global__ void rmsnorm_qk_kernel(
    const float* __restrict__ q_ptr,
    const float* __restrict__ k_ptr,
    const float* __restrict__ wq_ptr,
    const float* __restrict__ wk_ptr,
    float* __restrict__ oq_ptr,
    float* __restrict__ ok_ptr,
    int64_t N,
    float eps
) {
    constexpr int WARPS_PER_BLOCK = THREADS / WARP_SIZE;
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane = threadIdx.x % WARP_SIZE;
    const int global_warp_id = blockIdx.x * WARPS_PER_BLOCK + warp_id;
    const int total_warps = gridDim.x * WARPS_PER_BLOCK;
    constexpr float invD = 1.0f / static_cast<float>(HEAD_DIM);

    for (int64_t row = global_warp_id; row < N; row += total_warps) {
        const int h = static_cast<int>(row % static_cast<int64_t>(NUM_HEADS));

        const float4* q4 = reinterpret_cast<const float4*>(q_ptr + row * HEAD_DIM);
        const float4* k4 = reinterpret_cast<const float4*>(k_ptr + row * HEAD_DIM);
        const float4* wq4 = reinterpret_cast<const float4*>(wq_ptr + h * HEAD_DIM);
        const float4* wk4 = reinterpret_cast<const float4*>(wk_ptr + h * HEAD_DIM);

        // Streaming hint: these tensors are read once and never reused inside
        // the kernel, so do not allocate L1/L2 capacity for them.
        float4 qv = __ldcs(q4 + lane);
        float4 kv = __ldcs(k4 + lane);

        float q_sq = qv.x * qv.x + qv.y * qv.y + qv.z * qv.z + qv.w * qv.w;
        float k_sq = kv.x * kv.x + kv.y * kv.y + kv.z * kv.z + kv.w * kv.w;

        float q_sum = warp_reduce_sum(q_sq);
        float k_sum = warp_reduce_sum(k_sq);

        float q_inv = rsqrtf(q_sum * invD + eps);
        float k_inv = rsqrtf(k_sum * invD + eps);

        // Tiny per-head weight tables are L2-resident; read-only cache hint is
        // sufficient and avoids forcing them out of L1/L2 for reuse.
        float4 wqv = __ldg(wq4 + lane);
        float4 wkv = __ldg(wk4 + lane);

        float4 oqv = mul_rms_weight(qv, q_inv, wqv);
        float4 okv = mul_rms_weight(kv, k_inv, wkv);

        float4* oq4 = reinterpret_cast<float4*>(oq_ptr + row * HEAD_DIM);
        float4* ok4 = reinterpret_cast<float4*>(ok_ptr + row * HEAD_DIM);

        __stcs(oq4 + lane, oqv);
        __stcs(ok4 + lane, okv);
    }
}

// Dispatch to a 128-thread kernel tuned for the memory-bound regime.  The
// small/large launch-bound shapes are too small for CUDA graphs to help under
// cold-L2 CUPTI timing, so the win comes purely from bandwidth and launch
// efficiency.
std::tuple<at::Tensor, at::Tensor> run(
    at::Tensor query,
    at::Tensor key,
    at::Tensor weight_q,
    at::Tensor weight_k,
    double eps
) {
    const int64_t B = query.size(0);
    const int64_t S = query.size(1);
    const int64_t N = B * S * NUM_HEADS;

    // Ensure contiguous 2-D views for vectorized float4 I/O.  These are
    // no-ops when the inputs are already contiguous (the normal case).
    auto q2 = query.contiguous().reshape({N, HEAD_DIM});
    auto k2 = key.contiguous().reshape({N, HEAD_DIM});
    auto wq2 = weight_q.contiguous().reshape({NUM_HEADS, HEAD_DIM});
    auto wk2 = weight_k.contiguous().reshape({NUM_HEADS, HEAD_DIM});

    // Allocate contiguous output storage as a 2-D blob and return it viewed
    // as the original 4-D shape.
    auto out_q = at::empty({N, HEAD_DIM}, query.options());
    auto out_k = at::empty({N, HEAD_DIM}, key.options());

    const float* q_ptr = q2.data_ptr<float>();
    const float* k_ptr = k2.data_ptr<float>();
    const float* wq_ptr = wq2.data_ptr<float>();
    const float* wk_ptr = wk2.data_ptr<float>();
    float* oq_ptr = out_q.data_ptr<float>();
    float* ok_ptr = out_k.data_ptr<float>();

    constexpr int THREADS = 128;
    const int rows_per_block = THREADS / WARP_SIZE; // one row per warp
    const int64_t needed = (N + rows_per_block - 1) / rows_per_block;
    int blocks = static_cast<int>(std::min<int64_t>(MAX_BLOCKS, needed));
    if (blocks < 1) blocks = 1;

    cudaStream_t stream = at::cuda::getCurrentCUDAStream();
    rmsnorm_qk_kernel<THREADS>
        <<<blocks, THREADS, 0, stream>>>(
            q_ptr, k_ptr, wq_ptr, wk_ptr, oq_ptr, ok_ptr,
            N, static_cast<float>(eps));

    return std::make_tuple(out_q.view({B, S, NUM_HEADS, HEAD_DIM}),
                           out_k.view({B, S, NUM_HEADS, HEAD_DIM}));
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Fused per-head RMSNorm for Q and K");
}
